import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import InternshipModal from "../components/InternshipModal";

const dummyInternships = [
  {
    _id: "1",
    title: "Frontend Developer",
    company: "Google",
    category: "Web Development",
    location: "Remote",
    mode: "Online",
    description: "Build and maintain UI components using React.",
  },
  {
    _id: "2",
    title: "Data Analyst",
    company: "Microsoft",
    category: "Data Science",
    location: "Bangalore",
    mode: "Offline",
    description: "Analyze datasets and visualize insights.",
  },
];

export default function Internship() {
  const currentUser = JSON.parse(localStorage.getItem("currentUser"));
  const navigate = useNavigate();

  const [internships, setInternships] = useState([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingInternship, setEditingInternship] = useState(null);

  useEffect(() => {
    // Replace with real fetch from backend later
    setInternships(dummyInternships);
  }, []);

  const handleSave = (data) => {
    if (editingInternship) {
      setInternships((prev) =>
        prev.map((item) =>
          item._id === editingInternship._id ? { ...item, ...data } : item
        )
      );
    } else {
      setInternships((prev) => [
        ...prev,
        { ...data, _id: Date.now().toString() },
      ]);
    }
  };

  const handleDelete = (id) => {
    const confirm = window.confirm("Delete this internship?");
    if (confirm) {
      setInternships((prev) => prev.filter((item) => item._id !== id));
    }
  };

  const handleApply = (id) => {
    alert(`You have applied for internship ID: ${id}`);
  };

  return (
    <div className="p-4">
      <h2 className="text-2xl font-bold mb-4">Internships</h2>

      {(currentUser.role === "admin" || currentUser.role === "hr") && (
        <button
          onClick={() => setIsModalOpen(true)}
          className="bg-green-600 text-white px-4 py-2 rounded mb-4"
        >
          Post Internship
        </button>
      )}

      <div className="grid gap-4 md:grid-cols-2">
        {internships.map((internship) => (
          <div
            key={internship._id}
            className="border p-4 rounded shadow-md bg-white"
          >
            <h3 className="text-xl font-semibold">{internship.title}</h3>
            <p className="text-gray-600">{internship.company}</p>
            <p>
              <strong>Category:</strong> {internship.category}
            </p>
            <p>
              <strong>Location:</strong> {internship.location}
            </p>
            <p>
              <strong>Mode:</strong> {internship.mode}
            </p>
            <p className="text-sm mt-2">{internship.description}</p>

            {currentUser.role === "student" && (
              <button
                onClick={() => handleApply(internship._id)}
                className="mt-3 bg-blue-600 text-white px-3 py-1 rounded"
              >
                Apply
              </button>
            )}

            {(currentUser.role === "admin" || currentUser.role === "hr") && (
              <div className="flex gap-2 mt-3">
                <button
                  onClick={() => {
                    setEditingInternship(internship);
                    setIsModalOpen(true);
                  }}
                  className="bg-yellow-500 text-white px-3 py-1 rounded"
                >
                  Edit
                </button>
                {currentUser.role === "admin" && (
                  <button
                    onClick={() => handleDelete(internship._id)}
                    className="bg-red-600 text-white px-3 py-1 rounded"
                  >
                    Delete
                  </button>
                )}
              </div>
            )}
          </div>
        ))}
      </div>

      <InternshipModal
        isOpen={isModalOpen}
        onClose={() => {
          setIsModalOpen(false);
          setEditingInternship(null);
        }}
        onSave={handleSave}
        editingInternship={editingInternship}
      />
    </div>
  );
}
